#[derive(Clone)]
#[pyclass(unsendable, from_py_object)]
pub struct Registry {
    inner: Arc<std::sync::Mutex<xberg::Registry>>,
}

#[pymethods]
impl Registry {
    #[pyo3(signature = (id))]
    pub fn get(&self, id: String) -> Option<Preset> {
        self.inner.lock().unwrap().get(&id).map(|v| v.clone().into())
    }

    #[pyo3(signature = ())]
    pub fn summaries(&self) -> Vec<PresetSummary> {
        self.inner
            .lock()
            .unwrap()
            .summaries()
            .into_iter()
            .map(Into::into)
            .collect()
    }

    #[pyo3(signature = ())]
    pub fn len(&self) -> usize {
        self.inner.lock().unwrap().len()
    }

    #[pyo3(signature = ())]
    pub fn is_empty(&self) -> bool {
        self.inner.lock().unwrap().is_empty()
    }

    #[pyo3(signature = (preset_id, name))]
    pub fn sample_bytes(&self, preset_id: String, name: String) -> Option<Vec<u8>> {
        self.inner
            .lock()
            .unwrap()
            .sample_bytes(&preset_id, &name)
            .map(Into::into)
    }

    #[allow(clippy::missing_errors_doc)]
    #[pyo3(signature = (dir))]
    pub fn extend_from_dir(&self, dir: String) -> PyResult<usize> {
        let result = self
            .inner
            .lock()
            .unwrap()
            .extend_from_dir(std::path::Path::new(&dir))
            .map_err(|e| pyo3::exceptions::PyRuntimeError::new_err(e.to_string()))?;
        Ok(result)
    }

    #[allow(clippy::missing_errors_doc)]
    #[staticmethod]
    #[pyo3(signature = ())]
    pub fn load_embedded() -> PyResult<Registry> {
        xberg::Registry::load_embedded()
            .map(|val| Self {
                inner: Arc::new(std::sync::Mutex::new(val)),
            })
            .map_err(|e| pyo3::exceptions::PyRuntimeError::new_err(e.to_string()))
    }

    #[staticmethod]
    #[pyo3(signature = ())]
    pub fn global() -> Registry {
        Self {
            inner: Arc::new(std::sync::Mutex::new(xberg::Registry::global().clone())),
        }
    }
}

