#[allow(clippy::missing_errors_doc)]
#[pyfunction]
#[pyo3(signature = (input, config))]
pub fn extract<'py>(py: Python<'py>, input: ExtractInput, config: ExtractionConfig) -> PyResult<Bound<'py, PyAny>> {
    pyo3_async_runtimes::tokio::future_into_py(py, async move {
        let input_core: xberg::ExtractInput = input.into();

        let config_core: xberg::ExtractionConfig = config.into();

        let result = xberg::extract(input_core, &config_core)
            .await
            .map_err(|e| PyErr::new::<PyRuntimeError, _>(e.to_string()))?;
        let wrapped_result: ExtractionResult = ExtractionResult::from(result);
        Ok(wrapped_result)
    })
}

#[allow(clippy::missing_errors_doc)]
#[pyfunction]
#[pyo3(signature = (inputs, config))]
pub fn extract_batch<'py>(
    py: Python<'py>,
    inputs: Vec<ExtractInput>,
    config: ExtractionConfig,
) -> PyResult<Bound<'py, PyAny>> {
    pyo3_async_runtimes::tokio::future_into_py(py, async move {
        let inputs_core: Vec<_> = inputs.into_iter().map(Into::into).collect();

        let config_core: xberg::ExtractionConfig = config.into();

        let result = xberg::extract_batch(inputs_core, &config_core)
            .await
            .map_err(|e| PyErr::new::<PyRuntimeError, _>(e.to_string()))?;
        let wrapped_result: ExtractionResult = ExtractionResult::from(result);
        Ok(wrapped_result)
    })
}

