#[pyfunction]
pub fn register_validator(py: Python<'_>, backend: Py<PyAny>) -> PyResult<()> {
    let required_methods = ["validate"];
    let obj = backend.bind(py);
    for method in &required_methods {
        if !obj.hasattr(*method)? {
            return Err(pyo3::exceptions::PyAttributeError::new_err(format!(
                "Backend missing required method: {}",
                method
            )));
        }
    }

    let wrapper = PyValidatorBridge::new(backend)?;
    let arc: Arc<dyn xberg::Validator> = Arc::new(wrapper);

    py.detach(|| {
        let registry = xberg::plugins::registry::get_validator_registry();
        let mut registry = registry.write();
        registry
            .register(arc)
            .map_err(|e| pyo3::exceptions::PyRuntimeError::new_err(format!("Failed to register backend: {}", e)))
    })?;
    Ok(())
}

